    "source": "config_builder.add_column(\n    dd.SamplerColumnConfig(\n        name=\"customer\",\n        sampler_type=dd.SamplerType.PERSON_FROM_FAKER,\n        params=dd.PersonFromFakerSamplerParams(age_range=[18, 70], locale=\"en_US\"),\n    )\n)\n\nconfig_builder.add_column(\n    dd.SamplerColumnConfig(\n        name=\"number_of_stars\",\n        sampler_type=dd.SamplerType.UNIFORM,\n        params=dd.UniformSamplerParams(low=1, high=5),\n        convert_to=\"int\",  # Convert the sampled float to an integer.\n    )\n)\n\nconfig_builder.add_column(\n    dd.SamplerColumnConfig(\n        name=\"review_style\",\n        sampler_type=dd.SamplerType.CATEGORY,\n        params=dd.CategorySamplerParams(\n            values=[\"rambling\", \"brief\", \"detailed\", \"structured with bullet points\"],\n            weights=[1, 2, 2, 1],\n        ),\n    )\n)\n\ndata_designer.validate(config_builder)",
    "language": "python",
    "source_html": "config_builder<span style=\"color: #666\">.</span>add_column(\n    dd<span style=\"color: #666\">.</span>SamplerColumnConfig(\n        name<span style=\"color: #666\">=</span><span style=\"color: #4070A0\">&quot;customer&quot;</span>,\n        sampler_type<span style=\"color: #666\">=</span>dd<span style=\"color: #666\">.</span>SamplerType<span style=\"color: #666\">.</span>PERSON_FROM_FAKER,\n        params<span style=\"color: #666\">=</span>dd<span style=\"color: #666\">.</span>PersonFromFakerSamplerParams(age_range<span style=\"color: #666\">=</span>[<span style=\"color: #40A070\">18</span>, <span style=\"color: #40A070\">70</span>], locale<span style=\"color: #666\">=</span><span style=\"color: #4070A0\">&quot;en_US&quot;</span>),\n    )\n)\n\nconfig_builder<span style=\"color: #666\">.</span>add_column(\n    dd<span style=\"color: #666\">.</span>SamplerColumnConfig(\n        name<span style=\"color: #666\">=</span><span style=\"color: #4070A0\">&quot;number_of_stars&quot;</span>,\n        sampler_type<span style=\"color: #666\">=</span>dd<span style=\"color: #666\">.</span>SamplerType<span style=\"color: #666\">.</span>UNIFORM,\n        params<span style=\"color: #666\">=</span>dd<span style=\"color: #666\">.</span>UniformSamplerParams(low<span style=\"color: #666\">=</span><span style=\"color: #40A070\">1</span>, high<span style=\"color: #666\">=</span><span style=\"color: #40A070\">5</span>),\n        convert_to<span style=\"color: #666\">=</span><span style=\"color: #4070A0\">&quot;int&quot;</span>,  <span style=\"color: #60A0B0; font-style: italic\"># Convert the sampled float to an integer.</span>\n    )\n)\n\nconfig_builder<span style=\"color: #666\">.</span>add_column(\n    dd<span style=\"color: #666\">.</span>SamplerColumnConfig(\n        name<span style=\"color: #666\">=</span><span style=\"color: #4070A0\">&quot;review_style&quot;</span>,\n        sampler_type<span style=\"color: #666\">=</span>dd<span style=\"color: #666\">.</span>SamplerType<span style=\"color: #666\">.</span>CATEGORY,\n        params<span style=\"color: #666\">=</span>dd<span style=\"color: #666\">.</span>CategorySamplerParams(\n            values<span style=\"color: #666\">=</span>[<span style=\"color: #4070A0\">&quot;rambling&quot;</span>, <span style=\"color: #4070A0\">&quot;brief&quot;</span>, <span style=\"color: #4070A0\">&quot;detailed&quot;</span>, <span style=\"color: #4070A0\">&quot;structured with bullet points&quot;</span>],\n            weights<span style=\"color: #666\">=</span>[<span style=\"color: #40A070\">1</span>, <span style=\"color: #40A070\">2</span>, <span style=\"color: #40A070\">2</span>, <span style=\"color: #40A070\">1</span>],\n        ),\n    )\n)\n\ndata_designer<span style=\"color: #666\">.</span>validate(config_builder)\n",
